sql:
SELECT device_id, event_name, rssi, tx_power, advertising_interval, connection_interval
FROM ble_events
WHERE rssi > -70 AND device_id = 'DeviceA';

SELECT AVG(advertising_interval) AS avg_advertising_interval
FROM ble_events
WHERE bf_flag = 'Y';

SELECT event_name, event_type_id
FROM ble_events
WHERE event_id = 0;

SELECT event_name, device_id
FROM ble_events
WHERE event_name = 'HCI_LE_CONNECTION_COMPLETE_EVENT';

